
const POS_B64 = "";
const IDX_B64 = "";
function decode(b64, Ctor){
  const bin = atob(b64), bytes = new Uint8Array(bin.length);
  for (let i=0;i<bin.length;i++) bytes[i]=bin.charCodeAt(i);
  return new Ctor(bytes.buffer);
}

let _geo;
function getGeometry(){
  if (!_geo) {
    _geo = new THREE.BufferGeometry();
    _geo.setAttribute('position', new THREE.BufferAttribute(decode(POS_B64, Float32Array), 3));
    _geo.setIndex(new THREE.BufferAttribute(decode(IDX_B64, Uint16Array), 1));
    _geo.computeVertexNormals();
  }
  return _geo;
}

function init(canvas){
if (!canvas) return;                                      // FIX: voorkomt "Cannot read properties of null (reading 'width')"
// Maatreferentie: het canvas zelf, anders zijn ouder-element (de hero-sectie).
const box = canvas.parentElement || canvas;
const reduceMotion = window.matchMedia('(prefers-reduced-motion: reduce)').matches;

const renderer = new THREE.WebGLRenderer({ canvas, antialias:true, alpha:true, powerPreference:'high-performance' });
renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2)); // PERFORMANCE: cap retina
renderer.outputEncoding = THREE.sRGBEncoding;
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.05;

const scene = new THREE.Scene();
const camera = new THREE.PerspectiveCamera(45, 1, 0.1, 100);
camera.filmGauge = 35;                 // full-frame, zodat setFocalLength een echte 50mm-look geeft
camera.position.set(0, 0.92, 5.2);     // verder weg (was 3.05) zodat de aap kleiner in beeld staat
camera.lookAt(0, 0.92, 0);             // ingezoomd op het hoofd

// --- Subtiele omgevingsreflectie (zachte gradient) voor de glans op het zwart ---
const pmrem = new THREE.PMREMGenerator(renderer);
(function setEnv(){
  const c = document.createElement('canvas'); c.width = 16; c.height = 64;
  const g = c.getContext('2d');
  const grd = g.createLinearGradient(0, 0, 0, 64);
  grd.addColorStop(0.0, '#3a3a3a');  // boven: gedimd grijs voor zachte highlights (was #6e6e6e)
  grd.addColorStop(0.5, '#161616');
  grd.addColorStop(1.0, '#020202');  // onder: vrijwel zwart
  g.fillStyle = grd; g.fillRect(0, 0, 16, 64);
  const tex = new THREE.CanvasTexture(c);
  tex.mapping = THREE.EquirectangularReflectionMapping;
  scene.environment = pmrem.fromEquirectangular(tex).texture;
  tex.dispose();
})();

// --- Eén mooie, zachte key-light ---
const key = new THREE.DirectionalLight(0xffffff, 0.9); // veel zachter (was 2.0)
key.position.set(2.5, 4, 3);
scene.add(key);
scene.add(new THREE.AmbientLight(0x404040, 0.12)); // minimale neutrale fill (was 0.25)

const pivot = new THREE.Group();  // scroll-gestuurde turntable (wereld-Y)
const tilt = new THREE.Group();   // volgt de muis (gedempt)
const spin = new THREE.Group();   // basis-oriëntatie + zweven
tilt.add(spin); pivot.add(tilt); scene.add(pivot);

const geometry = getGeometry();  // gedeeld tussen alle apen — 1× gedecodeerd

const material = new THREE.MeshStandardMaterial({
  color: 0x000000, metalness: 0.5, roughness: 0.35
}); // pikzwart, alleen subtiele highlights tonen de vorm
const mesh = new THREE.Mesh(geometry, material);
spin.add(mesh);
spin.rotation.x = Math.PI / 2; // rechtop, naar voren gericht

const pointer = { x:0, y:0 }, target = { x:0, y:0 };
const MAX_TILT = 0.1, DAMP = 0.05; // subtielere muis-tilt (was 0.2)

// --- Scroll-gestuurde beweging ---
const SCROLL_ROT = Math.PI * 0.6; // hoeveel de aap draait over de hele hero (~108°)
const SCROLL_ZOOM = 0.18;         // hoeveel hij kleiner wordt tijdens het scrollen
let scrollProgress = 0;
function updateScroll(){
  // 0 wanneer de hero bovenaan staat, 1 wanneer hij volledig voorbij gescrold is
  const rect = box.getBoundingClientRect();
  const p = -rect.top / Math.max(rect.height, 1);
  scrollProgress = Math.min(Math.max(p, 0), 1);
}
window.addEventListener('scroll', updateScroll, { passive:true });
updateScroll();
window.addEventListener('pointermove', (e)=>{
  pointer.x = (e.clientX/window.innerWidth)*2 - 1;
  pointer.y = (e.clientY/window.innerHeight)*2 - 1;
  target.y = pointer.x * MAX_TILT;
  target.x = pointer.y * MAX_TILT;
}, { passive:true });

function resize(){
  // Gebruik de werkelijke CSS-grootte van het canvas (Webflow bepaalt de layout).
  const w = canvas.clientWidth || box.clientWidth;
  const h = canvas.clientHeight || box.clientHeight;
  if (!w || !h) return;                       // nog niet gelayout — sla over
  renderer.setSize(w, h, false);              // false = laat CSS de displaygrootte bepalen
  camera.aspect = w/h;
  camera.setFocalLength(50);                  // 50mm-lens look (zet fov op basis van aspect + filmGauge)
}
window.addEventListener('resize', resize); resize();
// Vang ook layout-wijzigingen op die geen window-resize zijn (Webflow, fonts, flex).
if (window.ResizeObserver) new ResizeObserver(resize).observe(box);

const clock = new THREE.Clock();
let running=false, rafId=null;
function frame(){
  const t = clock.getElapsedTime();
  // subtiel zweven op z'n plek (uit bij reduced motion)
  const amp = reduceMotion ? 0 : 1;
  spin.position.y = Math.sin(t * 0.7) * 0.04 * amp;   // subtieler op-en-neer (was 0.09)
  spin.rotation.z = Math.sin(t * 0.45) * 0.012 * amp; // subtielere kanteling (was 0.025)
  // muis-tilt, gedempt
  tilt.rotation.x += (target.x - tilt.rotation.x) * DAMP;
  tilt.rotation.y += (target.y - tilt.rotation.y) * DAMP;
  // scroll-gestuurde turntable + zoom-out, soepel gedempt
  const rotTarget = scrollProgress * SCROLL_ROT;
  const scaleTarget = 1 - scrollProgress * SCROLL_ZOOM;
  pivot.rotation.y += (rotTarget - pivot.rotation.y) * 0.08;
  const s = pivot.scale.x + (scaleTarget - pivot.scale.x) * 0.08;
  pivot.scale.set(s, s, s);
  renderer.render(scene, camera);
  rafId = requestAnimationFrame(frame);
}
function start(){ if(running) return; running=true; clock.getDelta(); frame(); }
function stop(){ running=false; if(rafId) cancelAnimationFrame(rafId); }

new IntersectionObserver(([e])=>{ e.isIntersecting ? start() : stop(); }, { threshold:0.05 }).observe(box); // PERFORMANCE
document.addEventListener('visibilitychange', ()=>{ document.hidden ? stop() : start(); });             // PERFORMANCE
start();
}

// Start een aap op elk canvas met [data-aap], plus het oude #scene voor backwards-compat.
function initAll(){
  const canvases = new Set(document.querySelectorAll('canvas[data-aap]'));
  const legacy = document.getElementById('scene');
  if (legacy) canvases.add(legacy);
  canvases.forEach(init);
}

// Wacht tot de DOM (incl. de canvassen) bestaat voordat we Three.js starten.
if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', initAll);
} else {
  initAll();
}
